171	// SetPreferredArchNodeAffinity sets the node affinity for the pod to the preferences given in the ClusterPodPlacementConfig.
172	// The configSource parameter identifies which configuration is setting the preferences (e.g., "ClusterPodPlacementConfig" or "PodPlacementConfig/my-ppc").
173	func (pod *Pod) SetPreferredArchNodeAffinity(nodeAffinity *plugins.NodeAffinityScoring, configSource string) {
174		log := ctrllog.FromContext(pod.Ctx())
175		if pod.Spec.Affinity == nil {
176			pod.Spec.Affinity = &corev1.Affinity{}
177		}
178	
179		if pod.Spec.Affinity.NodeAffinity == nil {
180			pod.Spec.Affinity.NodeAffinity = &corev1.NodeAffinity{}
181		}
182	
183		if pod.Spec.Affinity.NodeAffinity.PreferredDuringSchedulingIgnoredDuringExecution == nil {
184			pod.Spec.Affinity.NodeAffinity.PreferredDuringSchedulingIgnoredDuringExecution = []corev1.PreferredSchedulingTerm{}
185		}
186	
187		seenArchitectures := pod.getExistingPreferredArchitectures()
188		var preferredSchedulingTerms []corev1.PreferredSchedulingTerm
189		var skippedArchitectures []string
190		for _, nodeAffinityScoringPlatformTerm := range nodeAffinity.Platforms {
191			if !seenArchitectures[nodeAffinityScoringPlatformTerm.Architecture] {
192				preferredSchedulingTerm := corev1.PreferredSchedulingTerm{
193					Weight: nodeAffinityScoringPlatformTerm.Weight,
194					Preference: corev1.NodeSelectorTerm{
195						MatchExpressions: []corev1.NodeSelectorRequirement{
196							{
197								Key:      utils.ArchLabel,
198								Operator: corev1.NodeSelectorOpIn,
199								Values:   []string{nodeAffinityScoringPlatformTerm.Architecture},
200							},
201						},
202					},
203				}
204				preferredSchedulingTerms = append(preferredSchedulingTerms, preferredSchedulingTerm)
205				seenArchitectures[nodeAffinityScoringPlatformTerm.Architecture] = true
206				// Track that this architecture was applied from this source
207				pod.trackAffinitySource(nodeAffinityScoringPlatformTerm.Architecture, nodeAffinityScoringPlatformTerm.Weight, configSource, true)
208			} else {
209				skippedArchitectures = append(skippedArchitectures, nodeAffinityScoringPlatformTerm.Architecture)
210				// Track that this architecture was skipped from this source
211				pod.trackAffinitySource(nodeAffinityScoringPlatformTerm.Architecture, nodeAffinityScoringPlatformTerm.Weight, configSource, false)
212				log.Info("Preferred affinity for pod is already set", "Architecture", nodeAffinityScoringPlatformTerm.Architecture, "Weight", nodeAffinityScoringPlatformTerm.Weight, "Pod.Name", pod.Name, "Pod.Namespace", pod.Namespace, "ConfigSource", configSource)
213			}
214		}
215	
216		if preferredSchedulingTerms != nil {
217			pod.Spec.Affinity.NodeAffinity.PreferredDuringSchedulingIgnoredDuringExecution = append(
218				pod.Spec.Affinity.NodeAffinity.PreferredDuringSchedulingIgnoredDuringExecution, preferredSchedulingTerms...)
219			pod.EnsureLabel(utils.PreferredNodeAffinityLabel, utils.NodeAffinityLabelValueSet)
220		}
221		switch {
222		// Case 1: All architectures from this config were successfully added (no duplicates)
223		case preferredSchedulingTerms != nil && skippedArchitectures == nil:
224			pod.PublishEvent(corev1.EventTypeNormal, ArchitectureAwareNodeAffinitySet, fmt.Sprintf("%s source: %s", ArchitecturePreferredPredicateSetupMsg, configSource))
225			log.V(2).Info("Applied all architecture preferences from configuration", "ConfigSource", configSource)
226	
227		// Case 2: Some architectures were added, but some were skipped due to duplicates
228		case preferredSchedulingTerms != nil && skippedArchitectures != nil:
229			pod.PublishEvent(corev1.EventTypeNormal, ArchitectureAwareNodeAffinitySet, fmt.Sprintf("%s source: %s, skipped: %s", ArchitecturePreferredAffinityWithDuplicatesMsg, configSource, strings.Join(skippedArchitectures, ", ")))
230			log.V(2).Info("Applied some architecture preferences from configuration", "ConfigSource", configSource, "SkippedArchitectures", skippedArchitectures)
231	
232		// Case 3: All architectures from this config were already set
233		case preferredSchedulingTerms == nil && skippedArchitectures != nil:
234			pod.PublishEvent(corev1.EventTypeNormal, ArchitecturePreferredAffinityDuplicates, fmt.Sprintf("%s source: %s, architectures: %s", ArchitecturePreferredAffinityAllDuplicatesMsg, configSource, strings.Join(skippedArchitectures, ", ")))
235			log.V(2).Info("All architectures from configuration were already set", "ConfigSource", configSource, "SkippedArchitectures", skippedArchitectures)
236	
237		// Case 4: No architectures were provided in the config
238		default:
239			log.V(2).Info("No architecture preferences provided in configuration", "ConfigSource", configSource)
240		}
241	}
