243	// getExistingPreferredArchitectures finds all
244	// architectures that already have a preferred node affinity configured on the pod.
245	func (pod *Pod) getExistingPreferredArchitectures() map[string]bool {
246		seen := make(map[string]bool)
247		if pod.Spec.Affinity == nil || pod.Spec.Affinity.NodeAffinity == nil {
248			return seen
249		}
250	
251		for _, term := range pod.Spec.Affinity.NodeAffinity.PreferredDuringSchedulingIgnoredDuringExecution {
252			for _, expr := range term.Preference.MatchExpressions {
253				if expr.Key == utils.ArchLabel {
254					for _, value := range expr.Values {
255						seen[value] = true
256					}
257				}
258			}
259		}
260		return seen
261	}
